#include <iostream>
#include <cmath>

template <typename T>
T getAbsoluteValue(T value)
{
    if (value < 0) {
        return -value;
    }
    return value;
}

int main() {
    std::cout << getAbsoluteValue(-5) << std::endl;
    std::cout << getAbsoluteValue(0) << std::endl;
    std::cout << getAbsoluteValue(10) << std::endl;
    std::cout << getAbsoluteValue(-3.14f) << std::endl;
    std::cout << getAbsoluteValue(0.0f) << std::endl;
    std::cout << getAbsoluteValue(2.71f) << std::endl;
    std::cout << getAbsoluteValue(-9.81) << std::endl;
    std::cout << getAbsoluteValue(0.0) << std::endl;
    std::cout << getAbsoluteValue(1.2345) << std::endl;
    return 0;
}
